import React, { useState } from 'react';

function Payment({ plan, onSuccess, onCancel }) {
  const [phoneNumber, setPhoneNumber] = useState('');
  const [paymentCode, setPaymentCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);

  // خطط الأسعار المحدثة
  const plans = {
    monthly: { name: 'Mensuel', price: 3000, duration: '1 mois' },
    yearly: { name: 'Annuel', price: 15000, duration: '1 an' },
  };

  const selectedPlan = plans[plan] || plans.monthly;

  const handlePayment = () => {
    if (!phoneNumber || phoneNumber.length < 10) {
      alert('📱 Veuillez entrer un numéro de téléphone valide (ex: 0555123456)');
      return;
    }

    setLoading(true);

    // Simuler le paiement avec بريدي موب
    setTimeout(() => {
      setLoading(false);
      setStep(2);
      // Générer un code de paiement aléatoire
      const code = Math.floor(100000 + Math.random() * 900000);
      setPaymentCode(code);
      
      // Envoyer le code par SMS (simulé)
      alert(`📲 Code de paiement envoyé à ${phoneNumber}\n\nCode: ${code}\nMontant: ${selectedPlan.price} DA\nDurée: ${selectedPlan.duration}`);
    }, 2000);
  };

  const verifyPayment = () => {
    const enteredCode = prompt('📲 Entrez le code reçu par SMS:');
    if (enteredCode === String(paymentCode)) {
      alert(`✅ Paiement réussi!\n🎉 Abonnement ${selectedPlan.name} activé!\n📅 Durée: ${selectedPlan.duration}\n💰 Montant: ${selectedPlan.price} DA`);
      onSuccess();
    } else {
      alert('❌ Code incorrect. Veuillez réessayer.');
    }
  };

  return (
    <div style={styles.overlay}>
      <div style={styles.modal}>
        <button style={styles.closeBtn} onClick={onCancel}>✕</button>
        
        <div style={styles.header}>
          <h1 style={styles.title}>💳 Paiement بريدي موب</h1>
          <p style={styles.subtitle}>Abonnement {selectedPlan.name}</p>
        </div>

        {step === 1 ? (
          <div style={styles.content}>
            <div style={styles.planInfo}>
              <div style={styles.priceBox}>
                <span style={styles.priceAmount}>{selectedPlan.price} DA</span>
                <span style={styles.priceDuration}>/ {selectedPlan.duration}</span>
              </div>
              <p style={styles.planFeatures}>
                ✅ Messages illimités<br />
                ✅ Likes illimités<br />
                ✅ Profil en vedette
              </p>
            </div>

            <div style={styles.formGroup}>
              <label style={styles.label}>📱 Numéro de téléphone (Djezzy, Ooredoo, Mobilis)</label>
              <input
                type="tel"
                placeholder="0555123456"
                value={phoneNumber}
                onChange={(e) => setPhoneNumber(e.target.value.replace(/\D/g, ''))}
                style={styles.input}
                maxLength="10"
              />
              <p style={styles.hint}>Exemple: 0555123456</p>
            </div>

            <button 
              onClick={handlePayment} 
              style={styles.payBtn}
              disabled={loading}
            >
              {loading ? '⏳ Envoi en cours...' : '📲 Payer avec بريدي موب'}
            </button>

            <div style={styles.secureBadge}>
              🔒 Paiement sécurisé via بريدي موب
            </div>
          </div>
        ) : (
          <div style={styles.content}>
            <div style={styles.successIcon}>✅</div>
            <h2 style={styles.successTitle}>Code envoyé!</h2>
            <p style={styles.successText}>
              Un code de vérification a été envoyé au <br />
              <strong>{phoneNumber}</strong>
            </p>
            <button onClick={verifyPayment} style={styles.verifyBtn}>
              🔑 Vérifier le code
            </button>
            <button 
              onClick={() => setStep(1)} 
              style={styles.retryBtn}
            >
              🔄 Renvoyer le code
            </button>
          </div>
        )}

        <div style={styles.hearts}>
          <span style={styles.heart}>❤️</span>
          <span style={styles.heart}>💕</span>
          <span style={styles.heart}>❤️</span>
        </div>
      </div>
    </div>
  );
}

const styles = {
  overlay: {
    position: 'fixed',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    backgroundColor: 'rgba(0,0,0,0.7)',
    backdropFilter: 'blur(10px)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    zIndex: 1000,
    padding: '20px',
  },
  modal: {
    backgroundColor: 'white',
    borderRadius: '30px',
    padding: '40px',
    maxWidth: '450px',
    width: '100%',
    maxHeight: '90vh',
    overflowY: 'auto',
    position: 'relative',
    boxShadow: '0 30px 80px rgba(0,0,0,0.3)',
  },
  closeBtn: {
    position: 'absolute',
    top: '15px',
    right: '20px',
    background: 'none',
    border: 'none',
    fontSize: '30px',
    cursor: 'pointer',
    color: '#999',
  },
  header: {
    textAlign: 'center',
    marginBottom: '30px',
  },
  title: {
    fontSize: '2rem',
    fontWeight: 'bold',
    background: 'linear-gradient(45deg, #FF69B4, #4A90D9)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    marginBottom: '5px',
  },
  subtitle: {
    color: '#888',
    fontSize: '1rem',
  },
  content: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
  },
  planInfo: {
    backgroundColor: '#f8f8f8',
    borderRadius: '15px',
    padding: '20px',
    textAlign: 'center',
  },
  priceBox: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'baseline',
    gap: '5px',
    marginBottom: '10px',
  },
  priceAmount: {
    fontSize: '2.5rem',
    fontWeight: 'bold',
    color: '#FF1493',
  },
  priceDuration: {
    fontSize: '1.2rem',
    color: '#888',
  },
  planFeatures: {
    color: '#555',
    fontSize: '0.95rem',
    lineHeight: '1.8',
    margin: 0,
  },
  formGroup: {
    display: 'flex',
    flexDirection: 'column',
    gap: '8px',
  },
  label: {
    fontSize: '0.9rem',
    fontWeight: 'bold',
    color: '#555',
  },
  input: {
    padding: '14px 16px',
    borderRadius: '12px',
    border: '2px solid #e8e8e8',
    fontSize: '1.1rem',
    outline: 'none',
    textAlign: 'center',
  },
  hint: {
    fontSize: '0.8rem',
    color: '#999',
    margin: 0,
  },
  payBtn: {
    width: '100%',
    padding: '16px',
    borderRadius: '15px',
    border: 'none',
    background: 'linear-gradient(45deg, #FF6B6B, #FF1493)',
    color: 'white',
    fontSize: '1.2rem',
    fontWeight: 'bold',
    cursor: 'pointer',
    transition: 'transform 0.2s',
    boxShadow: '0 4px 20px rgba(255,20,147,0.35)',
  },
  secureBadge: {
    textAlign: 'center',
    color: '#4CAF50',
    fontSize: '0.9rem',
    fontWeight: 'bold',
  },
  successIcon: {
    fontSize: '4rem',
    textAlign: 'center',
  },
  successTitle: {
    textAlign: 'center',
    color: '#333',
    fontSize: '1.8rem',
  },
  successText: {
    textAlign: 'center',
    color: '#666',
    fontSize: '1rem',
    lineHeight: '1.6',
  },
  verifyBtn: {
    width: '100%',
    padding: '16px',
    borderRadius: '15px',
    border: 'none',
    background: 'linear-gradient(45deg, #4CAF50, #45a049)',
    color: 'white',
    fontSize: '1.2rem',
    fontWeight: 'bold',
    cursor: 'pointer',
    transition: 'transform 0.2s',
    boxShadow: '0 4px 20px rgba(76,175,80,0.35)',
  },
  retryBtn: {
    width: '100%',
    padding: '12px',
    borderRadius: '12px',
    border: '2px solid #e8e8e8',
    background: 'white',
    color: '#666',
    fontSize: '1rem',
    cursor: 'pointer',
    transition: 'transform 0.2s',
  },
  hearts: {
    marginTop: '20px',
    display: 'flex',
    justifyContent: 'center',
    gap: '15px',
  },
  heart: {
    fontSize: '1.5rem',
    animation: 'pulse 1.5s infinite',
  },
};

export default Payment;
